>
\ \ <title>3DM娓告垙缃\?-\ 鍏ㄧ悆鐑棬娓告垙鏀荤暐涓庤祫璁\?/title>
\ \ <style>
\ \ \ \ \*\ \{
\ \ \ \ \ \ margin:\ 0;
\ \ \ \ \ \ padding:\ 0;
\ \ \ \ \ \ box-sizing:\ border-box;
\ \ \ \ }

\ \ \ \ body\ \{
\ \ \ \ \ \ font-family:\ 'Microsoft\ YaHei',\ 'PingFang\ SC',\ sans-serif;
\ \ \ \ \ \ background:\ \#121212;
\ \ \ \ \ \ color:\ \#e0e0e0;
\ \ \ \ \ \ line-height:\ 1\.6;
\ \ \ \ }

\ \ \ \ a\ \{
\ \ \ \ \ \ text-decoration:\ none;
\ \ \ \ \ \ color:\ inherit;
\ \ \ \ }

\ \ \ \ /\*\ Header\ \*/
\ \ \ \ header\ \{
\ \ \ \ \ \ background:\ linear-gradient\(90deg,\ \#e74c3c,\ \#c0392b\);
\ \ \ \ \ \ padding:\ 10px\ 40px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ space-between;
\ \ \ \ \ \ position:\ sticky;
\ \ \ \ \ \ top:\ 0;
\ \ \ \ \ \ z-index:\ 1000;
\ \ \ \ }

\ \ \ \ \.logo\ \{
\ \ \ \ \ \ font-size:\ 1\.8em;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ text-shadow:\ 2px\ 2px\ 4px\ rgba\(0,0,0,0\.3\);
\ \ \ \ }

\ \ \ \ \.logo\ span\ \{
\ \ \ \ \ \ color:\ \#f39c12;
\ \ \ \ }

\ \ \ \ \.header-nav\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ gap:\ 25px;
\ \ \ \ }

\ \ \ \ \.header-nav\ a\ \{
\ \ \ \ \ \ color:\ rgba\(255,255,255,0\.9\);
\ \ \ \ \ \ text-decoration:\ none;
\ \ \ \ \ \ font-size:\ 0\.95em;
\ \ \ \ \ \ transition:\ color\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.header-nav\ a:hover\ \{
\ \ \ \ \ \ color:\ \#f39c12;
\ \ \ \ }

\ \ \ \ \.search-box\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ gap:\ 8px;
\ \ \ \ }

\ \ \ \ \.search-box\ input\ \{
\ \ \ \ \ \ padding:\ 8px\ 15px;
\ \ \ \ \ \ border:\ none;
\ \ \ \ \ \ border-radius:\ 4px;
\ \ \ \ \ \ background:\ rgba\(255,255,255,0\.95\);
\ \ \ \ \ \ color:\ \#333;
\ \ \ \ \ \ width:\ 200px;
\ \ \ \ }

\ \ \ \ \.search-box\ button\ \{
\ \ \ \ \ \ padding:\ 8px\ 20px;
\ \ \ \ \ \ background:\ \#2c3e50;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ border:\ none;
\ \ \ \ \ \ border-radius:\ 4px;
\ \ \ \ \ \ cursor:\ pointer;
\ \ \ \ }

\ \ \ \ /\*\ Banner\ \*/
\ \ \ \ \.banner\ \{
\ \ \ \ \ \ background:\ linear-gradient\(135deg,\ \#1a1a2e\ 0%,\ \#16213e\ 100%\);
\ \ \ \ \ \ padding:\ 100px\ 40px;
\ \ \ \ \ \ text-align:\ center;
\ \ \ \ \ \ position:\ relative;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ }

\ \ \ \ \.banner::before\ \{
\ \ \ \ \ \ content:\ '';
\ \ \ \ \ \ position:\ absolute;
\ \ \ \ \ \ top:\ 0;
\ \ \ \ \ \ left:\ 0;
\ \ \ \ \ \ right:\ 0;
\ \ \ \ \ \ bottom:\ 0;
\ \ \ \ \ \ background:\ radial-gradient\(circle\ at\ 30%\ 50%,\ rgba\(231,\ 76,\ 60,\ 0\.15\)\ 0%,\ transparent\ 50%\),
\ \ \ \ \ \ \ \ \ \ \ \ \ \ \ \ \ \ radial-gradient\(circle\ at\ 70%\ 50%,\ rgba\(243,\ 156,\ 18,\ 0\.1\)\ 0%,\ transparent\ 50%\);
\ \ \ \ }

\ \ \ \ \.banner\ h1\ \{
\ \ \ \ \ \ font-size:\ 3\.2em;
\ \ \ \ \ \ margin-bottom:\ 15px;
\ \ \ \ \ \ position:\ relative;
\ \ \ \ }

\ \ \ \ \.banner\ h1\ span\ \{
\ \ \ \ \ \ color:\ \#e74c3c;
\ \ \ \ }

\ \ \ \ \.banner\ p\ \{
\ \ \ \ \ \ font-size:\ 1\.15em;
\ \ \ \ \ \ color:\ \#888;
\ \ \ \ \ \ position:\ relative;
\ \ \ \ }

\ \ \ \ \.banner-tags\ \{
\ \ \ \ \ \ margin-top:\ 25px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ gap:\ 15px;
\ \ \ \ \ \ flex-wrap:\ wrap;
\ \ \ \ }

\ \ \ \ \.banner-tag\ \{
\ \ \ \ \ \ padding:\ 6px\ 18px;
\ \ \ \ \ \ border-radius:\ 20px;
\ \ \ \ \ \ font-size:\ 0\.9em;
\ \ \ \ \ \ background:\ rgba\(255,255,255,0\.1\);
\ \ \ \ \ \ border:\ 1px\ solid\ rgba\(255,255,255,0\.2\);
\ \ \ \ \ \ cursor:\ pointer;
\ \ \ \ \ \ transition:\ all\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.banner-tag:hover\ \{
\ \ \ \ \ \ background:\ \#e74c3c;
\ \ \ \ \ \ border-color:\ \#e74c3c;
\ \ \ \ }

\ \ \ \ /\*\ Container\ \*/
\ \ \ \ \.container\ \{
\ \ \ \ \ \ max-width:\ 1400px;
\ \ \ \ \ \ margin:\ 0\ auto;
\ \ \ \ \ \ padding:\ 40px;
\ \ \ \ }

\ \ \ \ /\*\ Section\ Title\ \*/
\ \ \ \ \.section-title\ \{
\ \ \ \ \ \ font-size:\ 1\.5em;
\ \ \ \ \ \ padding-bottom:\ 15px;
\ \ \ \ \ \ border-bottom:\ 3px\ solid\ \#e74c3c;
\ \ \ \ \ \ margin-bottom:\ 30px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 10px;
\ \ \ \ }

\ \ \ \ \.section-title\ \.hot\ \{
\ \ \ \ \ \ background:\ \#e74c3c;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ font-size:\ 0\.5em;
\ \ \ \ \ \ padding:\ 3px\ 8px;
\ \ \ \ \ \ border-radius:\ 3px;
\ \ \ \ }

\ \ \ \ \.section-title\ \.new\ \{
\ \ \ \ \ \ background:\ \#2ecc71;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ font-size:\ 0\.5em;
\ \ \ \ \ \ padding:\ 3px\ 8px;
\ \ \ \ \ \ border-radius:\ 3px;
\ \ \ \ }

\ \ \ \ \.section-title\ \.more\ \{
\ \ \ \ \ \ margin-left:\ auto;
\ \ \ \ \ \ font-size:\ 0\.6em;
\ \ \ \ \ \ color:\ \#888;
\ \ \ \ \ \ font-weight:\ normal;
\ \ \ \ }

\ \ \ \ /\*\ Game\ Grid\ \*/
\ \ \ \ \.game-grid\ \{
\ \ \ \ \ \ display:\ grid;
\ \ \ \ \ \ grid-template-columns:\ repeat\(auto-fill,\ minmax\(280px,\ 1fr\)\);
\ \ \ \ \ \ gap:\ 25px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.game-card\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 10px;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ \ \ transition:\ transform\ 0\.3s,\ box-shadow\ 0\.3s;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ }

\ \ \ \ \.game-card:hover\ \{
\ \ \ \ \ \ transform:\ translateY\(-5px\);
\ \ \ \ \ \ box-shadow:\ 0\ 15px\ 30px\ rgba\(0,0,0,0\.5\);
\ \ \ \ \ \ border-color:\ \#e74c3c;
\ \ \ \ }

\ \ \ \ \.game-cover\ \{
\ \ \ \ \ \ height:\ 180px;
\ \ \ \ \ \ background:\ \#2c3e50;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ font-size:\ 4em;
\ \ \ \ \ \ position:\ relative;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ }

\ \ \ \ \.game-cover\ img\ \{
\ \ \ \ \ \ width:\ 100%;
\ \ \ \ \ \ height:\ 100%;
\ \ \ \ \ \ object-fit:\ cover;
\ \ \ \ }

\ \ \ \ \.game-cover\ \.emoji\ \{
\ \ \ \ \ \ position:\ relative;
\ \ \ \ \ \ z-index:\ 1;
\ \ \ \ }

\ \ \ \ \.game-cover\ \.score\ \{
\ \ \ \ \ \ position:\ absolute;
\ \ \ \ \ \ top:\ 10px;
\ \ \ \ \ \ right:\ 10px;
\ \ \ \ \ \ background:\ rgba\(231,\ 76,\ 60,\ 0\.9\);
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ padding:\ 3px\ 10px;
\ \ \ \ \ \ border-radius:\ 4px;
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ z-index:\ 2;
\ \ \ \ }

\ \ \ \ \.game-info\ \{
\ \ \ \ \ \ padding:\ 20px;
\ \ \ \ }

\ \ \ \ \.game-title\ \{
\ \ \ \ \ \ font-size:\ 1\.2em;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ margin-bottom:\ 8px;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ }

\ \ \ \ \.game-tag\ \{
\ \ \ \ \ \ display:\ inline-block;
\ \ \ \ \ \ padding:\ 3px\ 10px;
\ \ \ \ \ \ border-radius:\ 4px;
\ \ \ \ \ \ font-size:\ 0\.75em;
\ \ \ \ \ \ margin-bottom:\ 10px;
\ \ \ \ }

\ \ \ \ \.tag-action\ \{\ background:\ rgba\(231,\ 76,\ 60,\ 0\.2\);\ color:\ \#e74c3c;\ }
\ \ \ \ \.tag-rpg\ \{\ background:\ rgba\(155,\ 89,\ 182,\ 0\.2\);\ color:\ \#9b59b6;\ }
\ \ \ \ \.tag-adventure\ \{\ background:\ rgba\(52,\ 152,\ 219,\ 0\.2\);\ color:\ \#3498db;\ }
\ \ \ \ \.tag-strategy\ \{\ background:\ rgba\(46,\ 204,\ 113,\ 0\.2\);\ color:\ \#2ecc71;\ }
\ \ \ \ \.tag-shooter\ \{\ background:\ rgba\(241,\ 196,\ 15,\ 0\.2\);\ color:\ \#f1c40f;\ }
\ \ \ \ \.tag-horror\ \{\ background:\ rgba\(192,\ 57,\ 43,\ 0\.2\);\ color:\ \#c0392b;\ }

\ \ \ \ \.game-desc\ \{
\ \ \ \ \ \ font-size:\ 0\.9em;
\ \ \ \ \ \ color:\ \#888;
\ \ \ \ \ \ line-height:\ 1\.6;
\ \ \ \ \ \ margin-bottom:\ 12px;
\ \ \ \ }

\ \ \ \ \.game-meta\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ justify-content:\ space-between;
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ color:\ \#666;
\ \ \ \ }

\ \ \ \ /\*\ News\ List\ \*/
\ \ \ \ \.news-list\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ flex-direction:\ column;
\ \ \ \ \ \ gap:\ 20px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.news-item\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 10px;
\ \ \ \ \ \ padding:\ 25px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ gap:\ 20px;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ \ \ transition:\ border-color\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.news-item:hover\ \{
\ \ \ \ \ \ border-color:\ \#e74c3c;
\ \ \ \ }

\ \ \ \ \.news-thumb\ \{
\ \ \ \ \ \ width:\ 200px;
\ \ \ \ \ \ height:\ 130px;
\ \ \ \ \ \ background:\ \#2c3e50;
\ \ \ \ \ \ border-radius:\ 8px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ font-size:\ 2\.5em;
\ \ \ \ \ \ flex-shrink:\ 0;
\ \ \ \ \ \ position:\ relative;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ }

\ \ \ \ \.news-thumb\ img\ \{
\ \ \ \ \ \ width:\ 100%;
\ \ \ \ \ \ height:\ 100%;
\ \ \ \ \ \ object-fit:\ cover;
\ \ \ \ }

\ \ \ \ \.news-thumb\ \.type-tag\ \{
\ \ \ \ \ \ position:\ absolute;
\ \ \ \ \ \ top:\ 8px;
\ \ \ \ \ \ left:\ 8px;
\ \ \ \ \ \ padding:\ 2px\ 8px;
\ \ \ \ \ \ border-radius:\ 3px;
\ \ \ \ \ \ font-size:\ 0\.7em;
\ \ \ \ \ \ background:\ rgba\(231,\ 76,\ 60,\ 0\.9\);
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ }

\ \ \ \ \.news-content\ \{
\ \ \ \ \ \ flex:\ 1;
\ \ \ \ }

\ \ \ \ \.news-title\ \{
\ \ \ \ \ \ font-size:\ 1\.15em;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ margin-bottom:\ 10px;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ }

\ \ \ \ \.news-title\ a:hover\ \{
\ \ \ \ \ \ color:\ \#e74c3c;
\ \ \ \ }

\ \ \ \ \.news-desc\ \{
\ \ \ \ \ \ font-size:\ 0\.9em;
\ \ \ \ \ \ color:\ \#888;
\ \ \ \ \ \ margin-bottom:\ 12px;
\ \ \ \ \ \ line-height:\ 1\.7;
\ \ \ \ }

\ \ \ \ \.news-meta\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ gap:\ 20px;
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ color:\ \#666;
\ \ \ \ }

\ \ \ \ \.news-meta\ span\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 5px;
\ \ \ \ }

\ \ \ \ /\*\ Strategy\ Section\ \*/
\ \ \ \ \.strategy-section\ \{
\ \ \ \ \ \ display:\ grid;
\ \ \ \ \ \ grid-template-columns:\ 2fr\ 1fr;
\ \ \ \ \ \ gap:\ 30px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.strategy-main\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 12px;
\ \ \ \ \ \ padding:\ 25px;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ }

\ \ \ \ \.strategy-item\ \{
\ \ \ \ \ \ padding:\ 20px\ 0;
\ \ \ \ \ \ border-bottom:\ 1px\ solid\ \#333;
\ \ \ \ }

\ \ \ \ \.strategy-item:last-child\ \{
\ \ \ \ \ \ border-bottom:\ none;
\ \ \ \ \ \ padding-bottom:\ 0;
\ \ \ \ }

\ \ \ \ \.strategy-item\ h4\ \{
\ \ \ \ \ \ font-size:\ 1\.1em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 8px;
\ \ \ \ }

\ \ \ \ \.strategy-item\ p\ \{
\ \ \ \ \ \ color:\ \#888;
\ \ \ \ \ \ font-size:\ 0\.9em;
\ \ \ \ \ \ line-height:\ 1\.7;
\ \ \ \ }

\ \ \ \ \.strategy-item\ \.step\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 10px;
\ \ \ \ \ \ margin-top:\ 10px;
\ \ \ \ }

\ \ \ \ \.step-num\ \{
\ \ \ \ \ \ width:\ 24px;
\ \ \ \ \ \ height:\ 24px;
\ \ \ \ \ \ background:\ \#e74c3c;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ border-radius:\ 50%;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ font-size:\ 0\.8em;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ }

\ \ \ \ \.strategy-sidebar\ \.side-card\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 12px;
\ \ \ \ \ \ padding:\ 20px;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ \ \ margin-bottom:\ 20px;
\ \ \ \ }

\ \ \ \ \.strategy-sidebar\ h4\ \{
\ \ \ \ \ \ font-size:\ 1em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 15px;
\ \ \ \ \ \ padding-bottom:\ 10px;
\ \ \ \ \ \ border-bottom:\ 2px\ solid\ \#e74c3c;
\ \ \ \ }

\ \ \ \ \.side-item\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ gap:\ 12px;
\ \ \ \ \ \ padding:\ 12px\ 0;
\ \ \ \ \ \ border-bottom:\ 1px\ solid\ \#333;
\ \ \ \ }

\ \ \ \ \.side-item:last-child\ \{
\ \ \ \ \ \ border-bottom:\ none;
\ \ \ \ }

\ \ \ \ \.side-num\ \{
\ \ \ \ \ \ font-size:\ 1\.5em;
\ \ \ \ \ \ color:\ \#e74c3c;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ width:\ 30px;
\ \ \ \ }

\ \ \ \ \.side-content\ h5\ \{
\ \ \ \ \ \ font-size:\ 0\.95em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 4px;
\ \ \ \ }

\ \ \ \ \.side-content\ p\ \{
\ \ \ \ \ \ font-size:\ 0\.8em;
\ \ \ \ \ \ color:\ \#666;
\ \ \ \ }

\ \ \ \ /\*\ Tools\ Section\ \*/
\ \ \ \ \.tools-grid\ \{
\ \ \ \ \ \ display:\ grid;
\ \ \ \ \ \ grid-template-columns:\ repeat\(auto-fill,\ minmax\(300px,\ 1fr\)\);
\ \ \ \ \ \ gap:\ 20px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.tool-card\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 10px;
\ \ \ \ \ \ padding:\ 20px;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 15px;
\ \ \ \ \ \ transition:\ all\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.tool-card:hover\ \{
\ \ \ \ \ \ border-color:\ \#e74c3c;
\ \ \ \ \ \ background:\ \#252525;
\ \ \ \ }

\ \ \ \ \.tool-icon\ \{
\ \ \ \ \ \ width:\ 50px;
\ \ \ \ \ \ height:\ 50px;
\ \ \ \ \ \ background:\ linear-gradient\(135deg,\ \#e74c3c,\ \#c0392b\);
\ \ \ \ \ \ border-radius:\ 10px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ font-size:\ 1\.5em;
\ \ \ \ }

\ \ \ \ \.tool-info\ \{
\ \ \ \ \ \ flex:\ 1;
\ \ \ \ }

\ \ \ \ \.tool-info\ h4\ \{
\ \ \ \ \ \ font-size:\ 1em;
\ \ \ \ \ \ margin-bottom:\ 5px;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ }

\ \ \ \ \.tool-info\ p\ \{
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ color:\ \#666;
\ \ \ \ }

\ \ \ \ \.tool-download\ \{
\ \ \ \ \ \ padding:\ 8px\ 15px;
\ \ \ \ \ \ background:\ \#e74c3c;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ border:\ none;
\ \ \ \ \ \ border-radius:\ 6px;
\ \ \ \ \ \ cursor:\ pointer;
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ transition:\ background\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.tool-download:hover\ \{
\ \ \ \ \ \ background:\ \#c0392b;
\ \ \ \ }

\ \ \ \ /\*\ Ranking\ Section\ \*/
\ \ \ \ \.ranking-section\ \{
\ \ \ \ \ \ display:\ grid;
\ \ \ \ \ \ grid-template-columns:\ repeat\(3,\ 1fr\);
\ \ \ \ \ \ gap:\ 25px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.ranking-card\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 12px;
\ \ \ \ \ \ padding:\ 25px;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ }

\ \ \ \ \.ranking-card\ h4\ \{
\ \ \ \ \ \ font-size:\ 1\.1em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 20px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 8px;
\ \ \ \ }

\ \ \ \ \.ranking-list\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ flex-direction:\ column;
\ \ \ \ \ \ gap:\ 15px;
\ \ \ \ }

\ \ \ \ \.ranking-item\ \{
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ gap:\ 12px;
\ \ \ \ \ \ padding:\ 10px;
\ \ \ \ \ \ border-radius:\ 8px;
\ \ \ \ \ \ transition:\ background\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.ranking-item:hover\ \{
\ \ \ \ \ \ background:\ \#252525;
\ \ \ \ }

\ \ \ \ \.rank-num\ \{
\ \ \ \ \ \ width:\ 28px;
\ \ \ \ \ \ height:\ 28px;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ border-radius:\ 6px;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ \ \ font-size:\ 0\.9em;
\ \ \ \ }

\ \ \ \ \.rank-1\ \{\ background:\ linear-gradient\(135deg,\ \#f39c12,\ \#e67e22\);\ color:\ \#fff;\ }
\ \ \ \ \.rank-2\ \{\ background:\ linear-gradient\(135deg,\ \#95a5a6,\ \#7f8c8d\);\ color:\ \#fff;\ }
\ \ \ \ \.rank-3\ \{\ background:\ linear-gradient\(135deg,\ \#cd6133,\ \#a04000\);\ color:\ \#fff;\ }
\ \ \ \ \.rank-other\ \{\ background:\ \#333;\ color:\ \#888;\ }

\ \ \ \ \.rank-info\ \{
\ \ \ \ \ \ flex:\ 1;
\ \ \ \ }

\ \ \ \ \.rank-info\ h5\ \{
\ \ \ \ \ \ font-size:\ 0\.95em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 2px;
\ \ \ \ }

\ \ \ \ \.rank-info\ p\ \{
\ \ \ \ \ \ font-size:\ 0\.8em;
\ \ \ \ \ \ color:\ \#666;
\ \ \ \ }

\ \ \ \ \.rank-value\ \{
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ color:\ \#e74c3c;
\ \ \ \ \ \ font-weight:\ bold;
\ \ \ \ }

\ \ \ \ /\*\ Hardware\ Section\ \*/
\ \ \ \ \.hardware-grid\ \{
\ \ \ \ \ \ display:\ grid;
\ \ \ \ \ \ grid-template-columns:\ repeat\(auto-fill,\ minmax\(300px,\ 1fr\)\);
\ \ \ \ \ \ gap:\ 25px;
\ \ \ \ \ \ margin-bottom:\ 60px;
\ \ \ \ }

\ \ \ \ \.hardware-card\ \{
\ \ \ \ \ \ background:\ \#1e1e1e;
\ \ \ \ \ \ border-radius:\ 12px;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ \ \ border:\ 1px\ solid\ \#333;
\ \ \ \ \ \ transition:\ all\ 0\.3s;
\ \ \ \ }

\ \ \ \ \.hardware-card:hover\ \{
\ \ \ \ \ \ border-color:\ \#e74c3c;
\ \ \ \ \ \ transform:\ translateY\(-3px\);
\ \ \ \ }

\ \ \ \ \.hardware-img\ \{
\ \ \ \ \ \ height:\ 160px;
\ \ \ \ \ \ background:\ \#2c3e50;
\ \ \ \ \ \ display:\ flex;
\ \ \ \ \ \ align-items:\ center;
\ \ \ \ \ \ justify-content:\ center;
\ \ \ \ \ \ font-size:\ 3em;
\ \ \ \ \ \ overflow:\ hidden;
\ \ \ \ }

\ \ \ \ \.hardware-img\ img\ \{
\ \ \ \ \ \ width:\ 100%;
\ \ \ \ \ \ height:\ 100%;
\ \ \ \ \ \ object-fit:\ cover;
\ \ \ \ }

\ \ \ \ \.hardware-info\ \{
\ \ \ \ \ \ padding:\ 20px;
\ \ \ \ }

\ \ \ \ \.hardware-info\ h4\ \{
\ \ \ \ \ \ font-size:\ 1\.1em;
\ \ \ \ \ \ color:\ \#fff;
\ \ \ \ \ \ margin-bottom:\ 8px;
\ \ \ \ }

\ \ \ \ \.hardware-info\ p\ \{
\ \ \ \ \ \ font-size:\ 0\.85em;
\ \ \ \ \ \ color:\ \#888;
